def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    start_lat = 37.7879
    start_lon = -122.4075
    warehouse_lat = 37.6213
    warehouse_lon = -122.3790

    # Step 1: Check Transit
    execution_log.append("Step 1: Checking transit density...")
    raw_transit = call_tool('osm-mcp-server_find_nearby_places', {
        'latitude': start_lat, 
        'longitude': start_lon, 
        'radius': 500, 
        'categories': ['public_transport']
    })
    execution_log.append(f"[RAW] {str(raw_transit)[:200]}")

    transit_data = json.loads(raw_transit) if isinstance(raw_transit, str) else raw_transit
    transit_result = transit_data.get('result', {})
    transit_count = 0

    # Count items in result structure
    if isinstance(transit_result, dict):
        for cat, subcats in transit_result.items():
            if isinstance(subcats, list):
                transit_count += len(subcats)
            elif isinstance(subcats, dict):
                for sub, items in subcats.items():
                    if isinstance(items, list):
                        transit_count += len(items)

    execution_log.append(f"Transit count: {transit_count}")

    if transit_count > 2:
        # Branch 1: High Transit
        execution_log.append("Branch 1: High Transit (> 2 stations)")

        # Check Cafes
        raw_amenity = call_tool('osm-mcp-server_find_nearby_places', {
            'latitude': start_lat,
            'longitude': start_lon,
            'radius': 500,
            'categories': ['amenity']
        })
        execution_log.append(f"[RAW] {str(raw_amenity)[:200]}")
        amenity_data = json.loads(raw_amenity) if isinstance(raw_amenity, str) else raw_amenity

        # Count cafes recursively
        def count_cafes(d):
            c = 0
            if isinstance(d, dict):
                for k, v in d.items():
                    if k == 'cafe' and isinstance(v, list):
                        c += len(v)
                    else:
                        c += count_cafes(v)
            return c

        cafe_count = count_cafes(amenity_data.get('result', {}))
        execution_log.append(f"Cafe count: {cafe_count}")

        if cafe_count > 5:
            # Sub-branch 1A: Saturated
            execution_log.append("Branch 1A: Saturated (> 5 cafes)")

            # Find Library
            libraries = []
            def find_libraries(d):
                libs = []
                if isinstance(d, dict):
                    for k, v in d.items():
                        if k == 'library' and isinstance(v, list):
                            libs.extend(v)
                        else:
                            libs.extend(find_libraries(v))
                return libs

            libraries = find_libraries(amenity_data.get('result', {}))

            if not libraries:
                result = "High Transit/Saturated: No library found."
            else:
                target_lib = libraries[0]
                lib_name = target_lib.get('name', 'Unknown Library')
                lib_lat = target_lib.get('lat', target_lib.get('latitude'))
                lib_lon = target_lib.get('lon', target_lib.get('longitude'))

                # Find fast food nearby
                raw_ff = call_tool('osm-mcp-server_find_nearby_places', {
                    'latitude': lib_lat,
                    'longitude': lib_lon,
                    'radius': 200,
                    'categories': ['amenity']
                })
                ff_data = json.loads(raw_ff) if isinstance(raw_ff, str) else raw_ff

                def count_ff(d):
                    c = 0
                    if isinstance(d, dict):
                        for k, v in d.items():
                            if k == 'fast_food' and isinstance(v, list):
                                c += len(v)
                            else:
                                c += count_ff(v)
                    return c
                ff_count = count_ff(ff_data.get('result', {}))

                result = f"High Transit/Saturated: {lib_name} has {ff_count} fast food spots nearby."

        else:
            # Sub-branch 1B: Opportunity
            execution_log.append("Branch 1B: Opportunity (<= 5 cafes)")

            raw_leisure = call_tool('osm-mcp-server_find_nearby_places', {
                'latitude': start_lat,
                'longitude': start_lon,
                'radius': 500,
                'categories': ['leisure']
            })
            leisure_data = json.loads(raw_leisure) if isinstance(raw_leisure, str) else raw_leisure

            parks = []
            def find_parks(d):
                p = []
                if isinstance(d, dict):
                    for k, v in d.items():
                        if k == 'park' and isinstance(v, list):
                            p.extend(v)
                        else:
                            p.extend(find_parks(v))
                return p
            parks = find_parks(leisure_data.get('result', {}))

            if not parks:
                result = "High Transit/Opportunity: No park found."
            else:
                target_park = parks[0]
                park_name = target_park.get('name', 'Unknown Park')
                park_lat = target_park.get('lat', target_park.get('latitude'))
                park_lon = target_park.get('lon', target_park.get('longitude'))

                raw_route = call_tool('osm-mcp-server_get_route_directions', {
                    'from_latitude': start_lat,
                    'from_longitude': start_lon,
                    'to_latitude': park_lat,
                    'to_longitude': park_lon,
                    'mode': 'foot'
                })
                route_data = json.loads(raw_route) if isinstance(raw_route, str) else raw_route
                duration = route_data.get('result', {}).get('summary', {}).get('duration', 'unknown')

                result = f"High Transit/Opportunity: {park_name} is {duration} seconds walk away."

    else:
        # Branch 2: Car Dependent
        execution_log.append("Branch 2: Car Dependent (<= 2 stations)")

        raw_parking = call_tool('osm-mcp-server_find_parking_facilities', {
            'latitude': start_lat,
            'longitude': start_lon,
            'radius': 500
        })
        execution_log.append(f"[RAW] {str(raw_parking)[:200]}")
        parking_data = json.loads(raw_parking) if isinstance(raw_parking, str) else raw_parking

        parking_list = parking_data.get('result', [])
        parking_count = len(parking_list) if isinstance(parking_list, list) else 0
        execution_log.append(f"Parking count: {parking_count}")

        if parking_count > 3:
            # Sub-branch 2A: High Parking
            execution_log.append("Branch 2A: High Parking (> 3)")

            raw_shop = call_tool('osm-mcp-server_find_nearby_places', {
                'latitude': start_lat,
                'longitude': start_lon,
                'radius': 500,
                'categories': ['shop']
            })
            shop_data = json.loads(raw_shop) if isinstance(raw_shop, str) else raw_shop

            supermarkets = []
            def find_supermarkets(d):
                s = []
                if isinstance(d, dict):
                    for k, v in d.items():
                        if k == 'supermarket' and isinstance(v, list):
                            s.extend(v)
                        else:
                            s.extend(find_supermarkets(v))
                return s
            supermarkets = find_supermarkets(shop_data.get('result', {}))

            if not supermarkets:
                result = "Car Dependent/High Parking: No supermarket found."
            else:
                target_shop = supermarkets[0]
                shop_name = target_shop.get('name', 'Unknown Shop')
                shop_lat = target_shop.get('lat', target_shop.get('latitude'))
                shop_lon = target_shop.get('lon', target_shop.get('longitude'))

                raw_route = call_tool('osm-mcp-server_get_route_directions', {
                    'from_latitude': warehouse_lat,
                    'from_longitude': warehouse_lon,
                    'to_latitude': shop_lat,
                    'to_longitude': shop_lon,
                    'mode': 'car'
                })
                route_data = json.loads(raw_route) if isinstance(raw_route, str) else raw_route
                dist = route_data.get('result', {}).get('summary', {}).get('distance', 'unknown')

                result = f"Car Dependent/High Parking: {shop_name} is {dist} meters from warehouse."
        else:
            # Sub-branch 2B: Low Parking
            execution_log.append("Branch 2B: Low Parking (<= 3)")

            raw_schools = call_tool('osm-mcp-server_find_schools_nearby', {
                'latitude': start_lat,
                'longitude': start_lon,
                'radius': 500
            })
            schools_data = json.loads(raw_schools) if isinstance(raw_schools, str) else raw_schools

            school_list = schools_data.get('result', [])
            if not school_list:
                result = "Car Dependent/Low Parking: No schools found."
            else:
                target_school = school_list[0]
                school_name = target_school.get('name', 'Unknown School')
                school_lat = target_school.get('lat', target_school.get('latitude'))
                school_lon = target_school.get('lon', target_school.get('longitude'))

                raw_commute = call_tool('osm-mcp-server_analyze_commute', {
                    'home_latitude': warehouse_lat,
                    'home_longitude': warehouse_lon,
                    'work_latitude': school_lat,
                    'work_longitude': school_lon,
                    'modes': ['car']
                })
                commute_data = json.loads(raw_commute) if isinstance(raw_commute, str) else raw_commute
                try:
                    duration = commute_data.get('result', {}).get('car', {}).get('summary', {}).get('duration')
                except:
                    duration = "unknown"

                result = f"Car Dependent/Low Parking: {school_name} commute is {duration} seconds."

    execution_log.append(f"Final Result: {result}")
    return "\n".join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    log = []

    # Step 1: Get RSI
    log.append("Step 1: Fetching RSI for IBM")
    rsi_args = {"symbol": "IBM", "interval": "1day", "time_period": 14}
    rsi_raw = call_tool("twelvedata_GetTimeSeriesRsi", rsi_args)
    log.append(f"[RAW RSI] {str(rsi_raw)[:200]}")

    rsi_data = json.loads(rsi_raw) if isinstance(rsi_raw, str) else rsi_raw

    # Defensive extraction
    values = rsi_data.get("values", [])
    if not values:
        return "Error: No RSI values returned.\n" + "\n".join(log)

    latest_rsi_str = values[0].get("rsi")
    if latest_rsi_str is None:
        return "Error: No RSI value found in latest record.\n" + "\n".join(log)

    try:
        rsi_val = float(latest_rsi_str)
    except ValueError:
        return f"Error: Invalid RSI value {latest_rsi_str}\n" + "\n".join(log)

    log.append(f"Latest RSI: {rsi_val}")

    result_summary = {"rsi": rsi_val, "branch": None, "secondary_data": None}

    # Branching Logic
    if rsi_val > 70:
        log.append("Branch 1: RSI > 70 (Overbought). Fetching MACD.")
        result_summary["branch"] = "Overbought -> MACD"
        macd_args = {"symbol": "IBM", "interval": "1day"}
        macd_raw = call_tool("twelvedata_GetTimeSeriesMacd", macd_args)
        log.append(f"[RAW MACD] {str(macd_raw)[:200]}")
        macd_data = json.loads(macd_raw) if isinstance(macd_raw, str) else macd_raw
        result_summary["secondary_data"] = macd_data.get("values", [])[:1] # Just latest

    elif rsi_val < 30:
        log.append("Branch 2: RSI < 30 (Oversold). Fetching Bollinger Bands.")
        result_summary["branch"] = "Oversold -> BBands"
        bb_args = {"symbol": "IBM", "interval": "1day", "time_period": 20, "sd": 2}
        bb_raw = call_tool("twelvedata_GetTimeSeriesBBands", bb_args)
        log.append(f"[RAW BBands] {str(bb_raw)[:200]}")
        bb_data = json.loads(bb_raw) if isinstance(bb_raw, str) else bb_raw
        result_summary["secondary_data"] = bb_data.get("values", [])[:1]

    else:
        log.append("Branch 3: RSI Neutral (30-70). Fetching Earnings.")
        result_summary["branch"] = "Neutral -> Earnings"
        earn_args = {"symbol": "IBM"}
        earn_raw = call_tool("twelvedata_GetEarnings", earn_args)
        log.append(f"[RAW Earnings] {str(earn_raw)[:200]}")
        earn_data = json.loads(earn_raw) if isinstance(earn_raw, str) else earn_raw
        result_summary["secondary_data"] = earn_data.get("earnings", [])[:1]

    log.append(f"Final Result Summary: {json.dumps(result_summary)}")
    return "\n".join(log)

