def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []
    owner = 'pallets'
    repo = 'flask'
    pr_number = 4500

    # Step 1: Get PR details
    execution_log.append(f"Step 1: Fetching PR #{pr_number} for {owner}/{repo}")
    raw_pr = call_tool('github_get_pull_request', {'owner': owner, 'repo': repo, 'pullNumber': pr_number})
    execution_log.append(f"[RAW PR] {str(raw_pr)[:200]}")

    pr_data = json.loads(raw_pr) if isinstance(raw_pr, str) else raw_pr

    # Defensive field access
    state = pr_data.get('state')
    merged_at = pr_data.get('merged_at')
    merge_commit_sha = pr_data.get('merge_commit_sha')

    execution_log.append(f"PR State: {state}, Merged At: {merged_at}")

    result_data = {}

    # Branching Logic
    if state == 'open':
        execution_log.append("Branch: PR is OPEN. Fetching changed files.")
        raw_files = call_tool('github_get_pull_request_files', {'owner': owner, 'repo': repo, 'pullNumber': pr_number})
        execution_log.append(f"[RAW FILES] {str(raw_files)[:200]}")
        files_data = json.loads(raw_files) if isinstance(raw_files, str) else raw_files
        result_data = {'status': 'open', 'files': files_data}

    elif state == 'closed' and merged_at is not None:
        execution_log.append("Branch: PR is MERGED. Fetching merge commit.")
        if merge_commit_sha:
            raw_commit = call_tool('github_get_commit', {'owner': owner, 'repo': repo, 'sha': merge_commit_sha})
            execution_log.append(f"[RAW COMMIT] {str(raw_commit)[:200]}")
            commit_data = json.loads(raw_commit) if isinstance(raw_commit, str) else raw_commit
            result_data = {'status': 'merged', 'commit': commit_data}
        else:
            result_data = {'status': 'merged', 'error': 'no_sha'}

    elif state == 'closed' and merged_at is None:
        execution_log.append("Branch: PR is CLOSED (Unmerged). Fetching comments.")
        raw_comments = call_tool('github_get_issue_comments', {'owner': owner, 'repo': repo, 'issue_number': pr_number})
        execution_log.append(f"[RAW COMMENTS] {str(raw_comments)[:200]}")
        comments_data = json.loads(raw_comments) if isinstance(raw_comments, str) else raw_comments
        result_data = {'status': 'closed_unmerged', 'comments': comments_data}

    else:
        execution_log.append(f"Branch: Unknown state {state}")
        result_data = {'status': 'unknown', 'raw': pr_data}

    execution_log.append(f"Final Aggregated Result: {str(result_data)[:500]}")
    return "\n".join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    owner = "facebook"
    repo = "react"
    issue_num = 28000

    # Step 1: Get Issue Details
    execution_log.append(f"Step 1: Getting issue #{issue_num} for {owner}/{repo}")
    raw_issue = call_tool('github_get_issue', {'owner': owner, 'repo': repo, 'issue_number': issue_num})
    execution_log.append(f"[RAW] {str(raw_issue)[:200]}")

    issue_data = json.loads(raw_issue) if isinstance(raw_issue, str) else raw_issue
    state = issue_data.get('state')
    # Defensive label extraction
    labels = [l.get('name') for l in issue_data.get('labels', [])]

    result = {}

    # Branch Logic
    if state == 'closed':
        execution_log.append("Condition Met: Issue is CLOSED -> Branch A")
        closed_by = issue_data.get('closed_by')
        if closed_by and isinstance(closed_by, dict):
            username = closed_by.get('login')
            if username:
                execution_log.append(f"Closed by: {username}. Searching repos...")
                raw_repos = call_tool('github_search_repositories', {'query': f"user:{username}", 'per_page': 5})
                execution_log.append(f"[RAW] {str(raw_repos)[:200]}")
                repos_data = json.loads(raw_repos) if isinstance(raw_repos, str) else raw_repos
                repo_list = [r.get('name') for r in repos_data.get('items', [])]
                result = {'branch': 'A', 'status': 'closed', 'data': repo_list}
            else:
                result = {'branch': 'A', 'status': 'closed', 'error': 'Username not found'}
        else:
             result = {'branch': 'A', 'status': 'closed', 'error': 'No closed_by info'}

    elif state == 'open':
        if 'Bug' in labels:
            execution_log.append("Condition Met: Issue is OPEN + Bug Label -> Branch B")
            # Find PRs
            raw_prs = call_tool('github_list_pull_requests', {'owner': owner, 'repo': repo, 'state': 'open', 'sort': 'created', 'direction': 'desc'})
            execution_log.append(f"[RAW] {str(raw_prs)[:200]}")
            prs_data = json.loads(raw_prs) if isinstance(raw_prs, str) else raw_prs

            target_pr = None
            if isinstance(prs_data, list):
                for pr in prs_data:
                    title = pr.get('title', '').lower()
                    if 'fix' in title:
                        target_pr = pr
                        break

            if target_pr:
                pr_num = target_pr.get('number')
                execution_log.append(f"Found PR #{pr_num}. Getting files...")
                raw_files = call_tool('github_get_pull_request_files', {'owner': owner, 'repo': repo, 'pullNumber': pr_num})
                execution_log.append(f"[RAW] {str(raw_files)[:200]}")
                files_data = json.loads(raw_files) if isinstance(raw_files, str) else raw_files
                file_list = [f.get('filename') for f in files_data if isinstance(f, dict)]
                result = {'branch': 'B', 'status': 'open', 'data': file_list}
            else:
                result = {'branch': 'B', 'status': 'open', 'data': 'No matching PR found'}
        else:
            execution_log.append("Condition Met: Issue is OPEN + No Bug Label -> Branch C")
            query = f"repo:{owner}/{repo} suspense"
            raw_code = call_tool('github_search_code', {'q': query, 'per_page': 1})
            execution_log.append(f"[RAW] {str(raw_code)[:200]}")
            code_data = json.loads(raw_code) if isinstance(raw_code, str) else raw_code
            items = code_data.get('items', [])
            first_path = items[0].get('path') if items else "No results"
            result = {'branch': 'C', 'status': 'open', 'data': first_path}
    else:
        result = {'branch': 'Unknown', 'status': str(state), 'data': None}

    execution_log.append(f"Final Aggregated Result: {json.dumps(result)}")
    return "\n".join(execution_log)
